  const perms = [
    { policy: policy.id, collection: 'product', action: 'read', fields: productFieldsNoPricing, permissions: {}, validation: {} },
    { policy: policy.id, collection: 'order', action: 'read', fields: orderFieldsNoValue, permissions: {}, validation: {} },
