    { policy: policy.id, collection: 'design', action: 'update', fields: ['*'], permissions: {}, validation: {} },
    ...readAll.map(col => ({ policy: policy.id, collection: col, action: 'read', fields: ['*'], permissions: {}, validation: {} })),
