  'gmail.com',
  'outlook.com',
  'hotmail.com',
  'yahoo.com',
  'clickup.com',
  'teams.mail.microsoft.com',
  'fireflies.ai',
  'sharepointonline.com',
  'avanan-mail.net',
];

const NOISE_DOMAIN_PREFIXES = ['notification.', 'news.', 'nl.'];

