  return `${DIRECTUS_URL}/auth/login/microsoft?redirect=${encodeURIComponent(returnTo)}`
}

export function assetUrl(id: string | null | undefined) {
  return id ? `${DIRECTUS_URL}/assets/${id}` : undefined
}

