    }

    try {
      const repository =
        await this.globalWorkspaceOrmManager.getRepository<MeetingNoteAttendeeWorkspaceEntity>(
          workspaceId,
          'meetingNoteAttendee',
          { shouldBypassPermissionChecks: true },
        );

