  private extractAddresses(email: EmailMessageWorkspaceEntity): string[] {
    const addresses: string[] = [];

    if (email.sender) {
      addresses.push(email.sender);
    }

    if (email.recipients) {
      for (const addr of email.recipients.split(',')) {
        const trimmed = addr.trim();

        if (trimmed) {
          addresses.push(trimmed);
        }
      }
    }

