      fields: [
        'id',
        'name',
        'email',
        'phone',
        'job_title',
        'contact_type',
        'scope',
        { retailer: ['id', 'name'] },
        { department: ['id', 'name'] },
      ],
      sort: ['name'],
      limit,
    }),
  ) as Promise<Buyer[]>
}

export async function fetchEmailMessages(limit = 300): Promise<CrmEmailMessage[]> {
  return directus.request(
