type Tab = 'pipeline' | 'companies' | 'contacts' | 'email' | 'meetings' | 'routing' | 'notes' | 'tasks' | 'approvals' | 'settings'

const ROUTING_STATUSES = ['UNROUTED', 'COMPANY_ONLY', 'COMPANY_DEPT', 'CUSTOMER_EMAIL_NO_COMPANY', 'ROUTED', 'SKIPPED']
